"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[9720],{26029(r,n,t){t.r(n),t.d(n,{assets:()=>i,contentTitle:()=>c,default:()=>_,frontMatter:()=>o,metadata:()=>e,toc:()=>a});const e=JSON.parse('{"id":"cpp14/shared-timed-mutex","title":"shared_timed_mutex\u4e0eshared_lock\uff08\u8bfb\u5199\u9501\uff09","description":"C++14 shared_timed_mutex\u4e0eshared_lock\uff08\u8bfb\u5199\u9501\uff09 \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp14/08-shared-timed-mutex.md","sourceDirName":"cpp14","slug":"/cpp14/08-shared-timed-mutex","permalink":"/LearnModernCpp/docs/cpp14/08-shared-timed-mutex","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp14","permalink":"/LearnModernCpp/docs/tags/cpp-14"},{"inline":true,"label":"shared_timed_mutex","permalink":"/LearnModernCpp/docs/tags/shared-timed-mutex"}],"version":"current","sidebarPosition":9,"frontMatter":{"sidebar_position":9,"slug":"08-shared-timed-mutex","title":"shared_timed_mutex\u4e0eshared_lock\uff08\u8bfb\u5199\u9501\uff09","description":"C++14 shared_timed_mutex\u4e0eshared_lock\uff08\u8bfb\u5199\u9501\uff09 \u6559\u5b66\u793a\u4f8b","tags":["cpp14","shared_timed_mutex"]},"sidebar":"docs","previous":{"title":"[[deprecated]]\u5c5e\u6027","permalink":"/LearnModernCpp/docs/cpp14/07-deprecated-attribute"},"next":{"title":"integer_sequence\u4e0eindex_sequence","permalink":"/LearnModernCpp/docs/cpp14/09-integer-sequence"}}');var s=t(74848),d=t(28453);const o={sidebar_position:9,slug:"08-shared-timed-mutex",title:"shared_timed_mutex\u4e0eshared_lock\uff08\u8bfb\u5199\u9501\uff09",description:"C++14 shared_timed_mutex\u4e0eshared_lock\uff08\u8bfb\u5199\u9501\uff09 \u6559\u5b66\u793a\u4f8b",tags:["cpp14","shared_timed_mutex"]},c="shared_timed_mutex\u4e0eshared_lock\uff08\u8bfb\u5199\u9501\uff09",i={},a=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function u(r){const n={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,d.R)(),...r.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(n.header,{children:(0,s.jsx)(n.h1,{id:"shared_timed_mutex\u4e0eshared_lock\u8bfb\u5199\u9501",children:"shared_timed_mutex\u4e0eshared_lock\uff08\u8bfb\u5199\u9501\uff09"})}),"\n",(0,s.jsx)(n.p,{children:"C++14 \u6807\u51c6\u5f15\u5165\u7684 shared_timed_mutex\u4e0eshared_lock\uff08\u8bfb\u5199\u9501\uff09 \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,s.jsx)(n.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,s.jsx)(n.pre,{children:(0,s.jsx)(n.code,{className:"language-cpp",metastring:'title="cpp14/08_shared_timed_mutex.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: shared_timed_mutex\u4e0eshared_lock\uff08\u8bfb\u5199\u9501\uff09\r\n * \u6240\u5c5e\u6807\u51c6: C++14\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: C++14\u5f15\u5165\u4e86std::shared_timed_mutex\u548cstd::shared_lock\uff0c\r\n *          \u5b9e\u73b0\u4e86\u8bfb\u5199\u9501\uff08\u5171\u4eab-\u72ec\u5360\u9501\uff09\u6a21\u5f0f\u3002\u591a\u4e2a\u7ebf\u7a0b\u53ef\u4ee5\u540c\u65f6\u6301\u6709\u5171\u4eab\u9501\r\n *          \uff08\u8bfb\u9501\uff09\uff0c\u4f46\u72ec\u5360\u9501\uff08\u5199\u9501\uff09\u4f1a\u6392\u65a5\u6240\u6709\u5176\u4ed6\u9501\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: C++11\u53ea\u6709mutex\u548crecursive_mutex\uff0c\u4e0d\u652f\u6301\u8bfb\u5199\u9501\u3002\u5728\u8bfb\u591a\u5199\u5c11\r\n *              \u7684\u573a\u666f\u4e2d\uff0c\u6240\u6709\u8bfb\u64cd\u4f5c\u90fd\u4e92\u65a5\u6548\u7387\u4f4e\u4e0b\u3002shared_timed_mutex\u5141\u8bb8\r\n *              \u591a\u4e2a\u8bfb\u8005\u5e76\u53d1\u8bbf\u95ee\uff0c\u53ea\u5728\u5199\u5165\u65f6\u624d\u72ec\u5360\uff0c\u5927\u5e45\u63d0\u5347\u5e76\u53d1\u6027\u80fd\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - shared_lock<>: \u4ee5\u5171\u4eab\u6a21\u5f0f\u9501\u5b9a\uff0c\u591a\u4e2a\u7ebf\u7a0b\u53ef\u540c\u65f6\u6301\u6709\uff08\u8bfb\u9501\uff09\r\n *   - unique_lock<>/lock_guard<>: \u4ee5\u72ec\u5360\u6a21\u5f0f\u9501\u5b9a\uff08\u5199\u9501\uff09\r\n *   - shared_timed_mutex\u652f\u6301\u8d85\u65f6\u64cd\u4f5c\uff08try_lock_for/try_lock_until\uff09\r\n *   - \u9002\u7528\u4e8e\u8bfb\u591a\u5199\u5c11\u7684\u573a\u666f\uff0c\u5982\u7f13\u5b58\u3001\u914d\u7f6e\u8bfb\u53d6\u7b49\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <shared_mutex>\r\n#include <mutex>\r\n#include <thread>\r\n#include <vector>\r\n#include <string>\r\n#include <chrono>\r\n#include <map>\r\n#include <sstream>\r\n#include <atomic>\r\n\r\n// \u7ebf\u7a0b\u5b89\u5168\u7684\u8f93\u51fa\r\nstd::mutex cout_mutex;\r\n\r\ntemplate<typename... Args>\r\nvoid safe_print(Args&&... args) {\r\n    std::lock_guard<std::mutex> lock(cout_mutex);\r\n    // \u4f7f\u7528initializer_list\u5c55\u5f00\u53c2\u6570\u5305\r\n    using expander = int[];\r\n    (void)expander{0, (void(std::cout << std::forward<Args>(args)), 0)...};\r\n    std::cout << "\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\n\r\n// \u7ebf\u7a0b\u5b89\u5168\u7684\u914d\u7f6e\u5b58\u50a8\uff08\u8bfb\u591a\u5199\u5c11\u7684\u5178\u578b\u573a\u666f\uff09\r\nclass ThreadSafeConfig {\r\npublic:\r\n    // \u8bfb\u64cd\u4f5c\u2014\u2014\u4f7f\u7528shared_lock\uff08\u5171\u4eab\u9501\uff09\r\n    std::string get(const std::string& key) const {\r\n        std::shared_lock<std::shared_timed_mutex> lock(mutex_);\r\n        auto it = data_.find(key);\r\n        return it != data_.end() ? it->second : "";\r\n    }\r\n\r\n    // \u5199\u64cd\u4f5c\u2014\u2014\u4f7f\u7528unique_lock\uff08\u72ec\u5360\u9501\uff09\r\n    void set(const std::string& key, const std::string& value) {\r\n        std::unique_lock<std::shared_timed_mutex> lock(mutex_);\r\n        data_[key] = value;\r\n    }\r\n\r\n    // \u8bfb\u53d6\u6240\u6709\u952e\u503c\u5bf9\r\n    std::map<std::string, std::string> get_all() const {\r\n        std::shared_lock<std::shared_timed_mutex> lock(mutex_);\r\n        return data_;\r\n    }\r\n\r\n    size_t size() const {\r\n        std::shared_lock<std::shared_timed_mutex> lock(mutex_);\r\n        return data_.size();\r\n    }\r\n\r\nprivate:\r\n    mutable std::shared_timed_mutex mutex_;\r\n    std::map<std::string, std::string> data_;\r\n};\r\n\r\nvoid basic_usage() {\r\n    std::cout << "--- basic_usage ---\\n";\r\n\r\n    ThreadSafeConfig config;\r\n\r\n    // \u5148\u5199\u5165\u4e00\u4e9b\u914d\u7f6e\r\n    config.set("host", "localhost");\r\n    config.set("port", "8080");\r\n    config.set("mode", "production");\r\n\r\n    std::cout << "  \u521d\u59cb\u914d\u7f6e:\\n";\r\n    std::cout << "    host = " << config.get("host") << "\\n";\r\n    std::cout << "    port = " << config.get("port") << "\\n";\r\n    std::cout << "    mode = " << config.get("mode") << "\\n";\r\n\r\n    // \u591a\u4e2a\u8bfb\u7ebf\u7a0b\u5e76\u53d1\u8bfb\u53d6\r\n    std::cout << "\\n  \u542f\u52a8\u591a\u4e2a\u8bfb\u7ebf\u7a0b\u5e76\u53d1\u8bfb\u53d6...\\n";\r\n\r\n    std::vector<std::thread> readers;\r\n    for (int i = 0; i < 4; ++i) {\r\n        readers.emplace_back([&config, i]() {\r\n            // \u591a\u4e2a\u8bfb\u7ebf\u7a0b\u53ef\u4ee5\u540c\u65f6\u6267\u884c\uff0c\u56e0\u4e3a\u5b83\u4eec\u4f7f\u7528shared_lock\r\n            auto host = config.get("host");\r\n            auto port = config.get("port");\r\n            safe_print("    \u8bfb\u7ebf\u7a0b", i, ": host=", host, ", port=", port);\r\n        });\r\n    }\r\n\r\n    for (auto& t : readers) t.join();\r\n\r\n    // \u5199\u7ebf\u7a0b\u4f1a\u72ec\u5360\u9501\r\n    std::cout << "\\n  \u5199\u7ebf\u7a0b\u66f4\u65b0\u914d\u7f6e...\\n";\r\n    std::thread writer([&config]() {\r\n        config.set("mode", "debug");\r\n        safe_print("    \u5199\u7ebf\u7a0b: mode \u5df2\u66f4\u65b0\u4e3a debug");\r\n    });\r\n    writer.join();\r\n\r\n    std::cout << "  \u66f4\u65b0\u540e mode = " << config.get("mode") << "\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\n\r\n// 1. \u8bfb\u5199\u9501 vs \u666e\u901amutex\u7684\u6027\u80fd\u5bf9\u6bd4\r\nclass RWCounter {\r\npublic:\r\n    void increment() {\r\n        std::unique_lock<std::shared_timed_mutex> lock(mutex_);\r\n        ++value_;\r\n    }\r\n\r\n    int get() const {\r\n        std::shared_lock<std::shared_timed_mutex> lock(mutex_);\r\n        return value_;\r\n    }\r\n\r\nprivate:\r\n    mutable std::shared_timed_mutex mutex_;\r\n    int value_ = 0;\r\n};\r\n\r\nclass MutexCounter {\r\npublic:\r\n    void increment() {\r\n        std::lock_guard<std::mutex> lock(mutex_);\r\n        ++value_;\r\n    }\r\n\r\n    int get() const {\r\n        std::lock_guard<std::mutex> lock(mutex_);\r\n        return value_;\r\n    }\r\n\r\nprivate:\r\n    mutable std::mutex mutex_;\r\n    int value_ = 0;\r\n};\r\n\r\n// 2. \u5e26\u8d85\u65f6\u7684\u9501\u64cd\u4f5c\r\nclass TimedResource {\r\npublic:\r\n    bool try_read(std::chrono::milliseconds timeout) {\r\n        // \u5c1d\u8bd5\u5728\u6307\u5b9a\u65f6\u95f4\u5185\u83b7\u53d6\u5171\u4eab\u9501\r\n        std::shared_lock<std::shared_timed_mutex> lock(mutex_, timeout);\r\n        if (lock.owns_lock()) {\r\n            // \u6210\u529f\u83b7\u53d6\u9501\r\n            return true;\r\n        }\r\n        return false;  // \u8d85\u65f6\r\n    }\r\n\r\n    bool try_write(std::chrono::milliseconds timeout) {\r\n        // \u5c1d\u8bd5\u5728\u6307\u5b9a\u65f6\u95f4\u5185\u83b7\u53d6\u72ec\u5360\u9501\r\n        std::unique_lock<std::shared_timed_mutex> lock(mutex_, timeout);\r\n        if (lock.owns_lock()) {\r\n            // \u6210\u529f\u83b7\u53d6\u9501\r\n            return true;\r\n        }\r\n        return false;  // \u8d85\u65f6\r\n    }\r\n\r\nprivate:\r\n    std::shared_timed_mutex mutex_;\r\n};\r\n\r\n// 3. \u591a\u8bfb\u5355\u5199\u7684\u7f13\u5b58\r\nclass Cache {\r\npublic:\r\n    // \u591a\u4e2a\u7ebf\u7a0b\u53ef\u4ee5\u540c\u65f6\u67e5\u8be2\u7f13\u5b58\r\n    bool lookup(int key, std::string& value) const {\r\n        std::shared_lock<std::shared_timed_mutex> lock(mutex_);\r\n        auto it = cache_.find(key);\r\n        if (it != cache_.end()) {\r\n            value = it->second;\r\n            return true;\r\n        }\r\n        return false;\r\n    }\r\n\r\n    // \u53ea\u6709\u4e00\u4e2a\u7ebf\u7a0b\u53ef\u4ee5\u66f4\u65b0\u7f13\u5b58\r\n    void update(int key, const std::string& value) {\r\n        std::unique_lock<std::shared_timed_mutex> lock(mutex_);\r\n        cache_[key] = value;\r\n    }\r\n\r\n    void clear() {\r\n        std::unique_lock<std::shared_timed_mutex> lock(mutex_);\r\n        cache_.clear();\r\n    }\r\n\r\nprivate:\r\n    mutable std::shared_timed_mutex mutex_;\r\n    std::map<int, std::string> cache_;\r\n};\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- advanced_usage ---\\n";\r\n\r\n    // 1. \u6027\u80fd\u5bf9\u6bd4\uff1a\u8bfb\u591a\u5199\u5c11\u573a\u666f\r\n    std::cout << "  [\u8bfb\u5199\u9501 vs mutex\u6027\u80fd\u5bf9\u6bd4]\\n";\r\n\r\n    const int NUM_READS = 100\'000;\r\n    const int NUM_READERS = 4;\r\n\r\n    // shared_timed_mutex\u6d4b\u8bd5\r\n    {\r\n        RWCounter rw_counter;\r\n        rw_counter.increment();  // \u8bbe\u7f6e\u521d\u59cb\u503c\r\n\r\n        auto start = std::chrono::high_resolution_clock::now();\r\n\r\n        std::vector<std::thread> threads;\r\n        for (int i = 0; i < NUM_READERS; ++i) {\r\n            threads.emplace_back([&rw_counter]() {\r\n                for (int j = 0; j < NUM_READS; ++j) {\r\n                    rw_counter.get();  // \u5e76\u53d1\u8bfb\r\n                }\r\n            });\r\n        }\r\n        for (auto& t : threads) t.join();\r\n\r\n        auto end = std::chrono::high_resolution_clock::now();\r\n        auto us = std::chrono::duration_cast<std::chrono::microseconds>(end - start).count();\r\n        std::cout << "    shared_timed_mutex: " << us << " \u5fae\u79d2\\n";\r\n    }\r\n\r\n    // \u666e\u901amutex\u6d4b\u8bd5\r\n    {\r\n        MutexCounter m_counter;\r\n        m_counter.increment();\r\n\r\n        auto start = std::chrono::high_resolution_clock::now();\r\n\r\n        std::vector<std::thread> threads;\r\n        for (int i = 0; i < NUM_READERS; ++i) {\r\n            threads.emplace_back([&m_counter]() {\r\n                for (int j = 0; j < NUM_READS; ++j) {\r\n                    m_counter.get();  // \u4e92\u65a5\u8bfb\r\n                }\r\n            });\r\n        }\r\n        for (auto& t : threads) t.join();\r\n\r\n        auto end = std::chrono::high_resolution_clock::now();\r\n        auto us = std::chrono::duration_cast<std::chrono::microseconds>(end - start).count();\r\n        std::cout << "    \u666e\u901amutex:          " << us << " \u5fae\u79d2\\n";\r\n    }\r\n\r\n    std::cout << "    (\u8bfb\u591a\u573a\u666f\u4e0bshared_timed_mutex\u901a\u5e38\u66f4\u5feb)\\n";\r\n\r\n    // 2. \u8d85\u65f6\u64cd\u4f5c\r\n    std::cout << "\\n  [\u8d85\u65f6\u9501\u64cd\u4f5c]\\n";\r\n    TimedResource resource;\r\n    bool got_read = resource.try_read(std::chrono::milliseconds(100));\r\n    bool got_write = resource.try_write(std::chrono::milliseconds(100));\r\n    std::cout << "    try_read(100ms)  = " << (got_read ? "\u6210\u529f" : "\u8d85\u65f6") << "\\n";\r\n    std::cout << "    try_write(100ms) = " << (got_write ? "\u6210\u529f" : "\u8d85\u65f6") << "\\n";\r\n\r\n    // 3. \u7f13\u5b58\u573a\u666f\r\n    std::cout << "\\n  [\u591a\u8bfb\u5355\u5199\u7f13\u5b58]\\n";\r\n    Cache cache;\r\n\r\n    // \u5199\u5165\u4e00\u4e9b\u6570\u636e\r\n    for (int i = 0; i < 10; ++i) {\r\n        cache.update(i, "value_" + std::to_string(i));\r\n    }\r\n\r\n    // \u591a\u7ebf\u7a0b\u5e76\u53d1\u67e5\u8be2\r\n    std::atomic<int> hits{0};\r\n    std::atomic<int> misses{0};\r\n\r\n    std::vector<std::thread> readers;\r\n    for (int t = 0; t < 4; ++t) {\r\n        readers.emplace_back([&cache, &hits, &misses]() {\r\n            for (int i = 0; i < 15; ++i) {\r\n                std::string val;\r\n                if (cache.lookup(i, val)) {\r\n                    hits.fetch_add(1);\r\n                } else {\r\n                    misses.fetch_add(1);\r\n                }\r\n            }\r\n        });\r\n    }\r\n    for (auto& t : readers) t.join();\r\n\r\n    std::cout << "    \u7f13\u5b58\u547d\u4e2d: " << hits.load() << "\\n";\r\n    std::cout << "    \u7f13\u5b58\u672a\u4e2d: " << misses.load() << "\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9\u4e0e\u9677\u9631\r\n// ============================================================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- pitfalls ---\\n";\r\n\r\n    // \u9677\u96311\uff1a\u8bfb\u5199\u9501\u4e0d\u9632\u6b62\u5199\u9965\u997f\u6216\u8bfb\u9965\u997f\r\n    std::cout << "  \u9677\u96311: \u8bfb\u5199\u9501\u7684\u9965\u997f\u95ee\u9898\\n";\r\n    std::cout << "    \u5982\u679c\u8bfb\u8005\u4e00\u76f4\u6301\u6709\u9501\uff0c\u5199\u8005\u53ef\u80fd\u6c38\u8fdc\u7b49\u4e0d\u5230\u673a\u4f1a\uff08\u5199\u9965\u997f\uff09\\n";\r\n    std::cout << "    \u53cd\u4e4b\u4ea6\u7136\u3002\u5177\u4f53\u884c\u4e3a\u53d6\u51b3\u4e8e\u5b9e\u73b0\\n";\r\n\r\n    // \u9677\u96312\uff1ashared_timed_mutex\u6bd4\u666e\u901amutex\u5f00\u9500\u66f4\u5927\r\n    std::cout << "\\n  \u9677\u96312: \u4e0d\u8981\u5728\u5199\u591a\u8bfb\u5c11\u573a\u666f\u4f7f\u7528\u8bfb\u5199\u9501\\n";\r\n    std::cout << "    shared_timed_mutex\u7684\u9501\u64cd\u4f5c\u6bd4mutex\u66f4\u91cd\\n";\r\n    std::cout << "    \u53ea\u6709\u8bfb\u8fdc\u591a\u4e8e\u5199\u65f6\u624d\u6709\u6027\u80fd\u4f18\u52bf\\n";\r\n\r\n    // \u9677\u96313\uff1a\u4e0d\u8981\u5728\u6301\u6709\u5171\u4eab\u9501\u65f6\u5c1d\u8bd5\u83b7\u53d6\u72ec\u5360\u9501\uff08\u6b7b\u9501\uff09\r\n    std::cout << "\\n  \u9677\u96313: \u9501\u5347\u7ea7\u4f1a\u5bfc\u81f4\u6b7b\u9501\\n";\r\n    std::cout << "    // \u6b7b\u9501\u793a\u4f8b\uff08\u4e0d\u8981\u8fd9\u6837\u505a\uff01\uff09\uff1a\\n";\r\n    std::cout << "    // shared_lock<shared_timed_mutex> read_lock(mtx);\\n";\r\n    std::cout << "    // unique_lock<shared_timed_mutex> write_lock(mtx); // \u6b7b\u9501!\\n";\r\n    std::cout << "    \u6b63\u786e\u505a\u6cd5\uff1a\u5148\u91ca\u653e\u5171\u4eab\u9501\uff0c\u518d\u83b7\u53d6\u72ec\u5360\u9501\\n";\r\n\r\n    // \u9677\u96314\uff1ashared_lock\u53ea\u80fd\u7528\u4e8eshared_timed_mutex\uff08\u6216shared_mutex in C++17\uff09\r\n    std::cout << "\\n  \u9677\u96314: shared_lock\u4e0d\u80fd\u7528\u4e8e\u666e\u901amutex\\n";\r\n    std::cout << "    std::shared_lock<std::mutex> lock(m); // \u7f16\u8bd1\u9519\u8bef!\\n";\r\n    std::cout << "    \u5fc5\u987b\u642d\u914dshared_timed_mutex\u4f7f\u7528\\n";\r\n\r\n    // \u9677\u96315\uff1aC++14\u53ea\u6709shared_timed_mutex\uff0c\u6ca1\u6709shared_mutex\r\n    std::cout << "\\n  \u9677\u96315: C++14 vs C++17\\n";\r\n    std::cout << "    C++14: shared_timed_mutex (\u652f\u6301\u8d85\u65f6)\\n";\r\n    std::cout << "    C++17: \u589e\u52a0\u4e86 shared_mutex (\u4e0d\u652f\u6301\u8d85\u65f6\uff0c\u4f46\u66f4\u8f7b\u91cf)\\n";\r\n    std::cout << "    \u5982\u679c\u4e0d\u9700\u8981\u8d85\u65f6\u529f\u80fd\uff0cC++17\u7684shared_mutex\u66f4\u5408\u9002\\n";\r\n\r\n    // \u9677\u96316\uff1a\u8bfb\u5199\u9501\u4e0d\u80fd\u66ff\u4ee3\u7ec6\u7c92\u5ea6\u7684\u5e76\u53d1\u6570\u636e\u7ed3\u6784\r\n    std::cout << "\\n  \u9677\u96316: \u8bfb\u5199\u9501\u4e0d\u662f\u4e07\u80fd\u7684\\n";\r\n    std::cout << "    \u9ad8\u5e76\u53d1\u573a\u666f\u53ef\u80fd\u9700\u8981\u65e0\u9501\u6570\u636e\u7ed3\u6784\u6216\u5206\u6bb5\u9501\\n";\r\n    std::cout << "    \u8bfb\u5199\u9501\u9002\u5408\u4e2d\u4f4e\u5e76\u53d1\u7684\u8bfb\u591a\u5199\u5c11\u573a\u666f\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "===== shared_timed_mutex\u4e0eshared_lock - C++14 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,s.jsx)(n.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsx)(n.li,{children:(0,s.jsx)(n.a,{href:"https://en.cppreference.com/w/cpp/thread/mutex",children:"cppreference: shared_timed_mutex\u4e0eshared_lock\uff08\u8bfb\u5199\u9501\uff09"})}),"\n"]})]})}function _(r={}){const{wrapper:n}={...(0,d.R)(),...r.components};return n?(0,s.jsx)(n,{...r,children:(0,s.jsx)(u,{...r})}):u(r)}},28453(r,n,t){t.d(n,{R:()=>o,x:()=>c});var e=t(96540);const s={},d=e.createContext(s);function o(r){const n=e.useContext(d);return e.useMemo(function(){return"function"==typeof r?r(n):{...n,...r}},[n,r])}function c(r){let n;return n=r.disableParentContext?"function"==typeof r.components?r.components(s):r.components||s:o(r.components),e.createElement(d.Provider,{value:n},r.children)}}}]);